import React, { useState, useEffect } from "react";

function RouteForm() {
  const [stations, setStations] = useState([]);
  const [departure, setDeparture] = useState("");
  const [arrival, setArrival] = useState("");

  useEffect(() => {
    fetch("http://localhost:5050/stations")
      .then(res => res.json())
      .then(data => setStations(data))
      .catch(err => console.error(err));
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!departure || !arrival) {
      alert("Выберите обе станции");
      return;
    }

    try {
      const res = await fetch("http://localhost:5050/routes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ departure_station: departure, arrival_station: arrival })
      });

      const data = await res.json();
      if (!res.ok) {
        alert(data.error || "Ошибка");
        return;
      }

      alert("Маршрут добавлен ✅");
      setDeparture("");
      setArrival("");
    } catch (err) {
      console.error(err);
      alert("Ошибка соединения");
    }
  };

  return (
    <div>
      <h2>Add Route</h2>
      <form onSubmit={handleSubmit}>
        <select value={departure} onChange={e => setDeparture(e.target.value)}>
          <option value="">Выберите станцию отправления</option>
          {stations.map(st => (
            <option key={st.id} value={st.name}>{st.name}</option>
          ))}
        </select>

        <select value={arrival} onChange={e => setArrival(e.target.value)}>
          <option value="">Выберите станцию прибытия</option>
          {stations.map(st => (
            <option key={st.id} value={st.name}>{st.name}</option>
          ))}
        </select>

        <button type="submit">Add</button>
      </form>
    </div>
  );
}

export default RouteForm;
